4	 * Trigger bindings — map a successful orchestrator run to a suite so the suite
5	 * runs on that pipeline/DAG's success (CLAUDE.md §4). Provider-agnostic: the
6	 * composite key (`provider`, `pipeline_or_dag_id`, `env`) → `suite_id`. Managing
7	 * a binding needs `edit` on the suite (backend-gated); listing needs `view`.
8	 * Orchestration providers are *never* a datasource — this is the only place a
9	 * pipeline/DAG id is bound to a suite.
10	 */
11	
12	export const ORCHESTRATION_PROVIDERS = ['adf', 'airflow'] as const;
13	export type OrchestrationProvider = (typeof ORCHESTRATION_PROVIDERS)[number];
14	
15	export const PROVIDER_LABELS: Record<OrchestrationProvider, string> = {
16	  adf: 'Azure Data Factory',
17	  airflow: 'Apache Airflow',
18	};
19	
20	/** Mirrors the backend `TriggerBindingRead`. */
21	export interface TriggerBinding {
22	  id: string;
23	  provider: OrchestrationProvider;
24	  pipeline_or_dag_id: string;
25	  env: string;

1	import { api } from './client';
2	
3	/**
4	 * Runs / results / pipeline-runs API — the read surface behind the Results page
5	 * (backend `runs.py`, PR-C0b). The DQ-run reads are suite-scoped: the backend
6	 * filters to suites the caller can access, so this client never has to. Manual
7	 * run *triggering* (`runSuite` → `POST /suites/{id}/run`) lives here too, since
8	 * it produces a `Run`.
9	 */
10	
11	/** Run execution lifecycle — `status` is execution, not data quality. */
12	export const RUN_STATUSES = ['queued', 'running', 'succeeded', 'failed', 'cancelled'] as const;
13	export type RunStatus = (typeof RUN_STATUSES)[number];
14	
15	/** Result severity tier (ADR 0005) + the two operational statuses (#122). */
16	export type ResultStatus = 'pass' | 'warn' | 'fail' | 'critical' | 'skip' | 'error';
17	
18	/** Mirrors the backend `RunRead`. */
19	export interface Run {
20	  id: string;
21	  suite_id: string;
22	  status: RunStatus;
23	  triggered_by: string | null;
24	  started_at: string | null;
25	  finished_at: string | null;
26	  created_at: string;
27	  /** Data-quality outcome — distinct from `status` (execution): a run is
28	   *  `succeeded` even when checks fail. `worst_severity` is null when all passed. */
29	  checks_total: number;
30	  checks_passed: number;
31	  worst_severity: 'warn' | 'fail' | 'critical' | null;
32	}
33	
34	/** Mirrors `ResultRead`. `sample_failures` is the GX failing-row sample, redacted
35	 *  at the API boundary (#226): the numeric counts are kept; the raw cell values
36	 *  are masked to `"<redacted>"`. */
37	export interface Result {
38	  id: string;
39	  check_id: string;
40	  status: ResultStatus;
41	  metric_value: number | null;
42	  duration_ms: number | null;
43	  observed_value: Record<string, unknown> | null;
44	  expected_value: Record<string, unknown> | null;
45	  sample_failures: Record<string, unknown> | null;
46	}
47	
48	/** Mirrors `RunDetailRead` — a run plus its result rows. */
49	export interface RunDetail extends Run {
50	  results: Result[];
51	}
52	
53	/** Mirrors `CheckProgressRead` — `status` is null while the check is pending. */
54	export interface CheckProgress {
55	  check_id: string;
56	  name: string;
57	  status: ResultStatus | null;
58	}
59	
60	/**
61	 * Mirrors `RunProgressRead` — the compact live-progress shape the run-progress
62	 * UI polls: run lifecycle + per-check resolution + a status histogram. Lighter
63	 * than the full run+results detail (`getRun`).
64	 */
65	export interface RunProgress {
66	  run_id: string;
67	  suite_id: string;
68	  status: RunStatus;
69	  total_checks: number;
70	  completed_checks: number;
71	  counts: Record<string, number>;
72	  checks: CheckProgress[];
73	  started_at: string | null;
74	  finished_at: string | null;
75	}
76	
77	/** Mirrors `PipelineRunRead` — a monitored orchestrator run (`pipeline_runs` ≠ `runs`). */
78	export interface PipelineRun {
79	  id: string;
80	  provider: 'adf' | 'airflow';
81	  connection_id: string;
82	  provider_run_id: string;
83	  pipeline_or_dag_id: string;
84	  env: string;
85	  status: string;
86	  started_at: string | null;
87	  finished_at: string | null;
88	  failure_reason: string | null;
89	  created_at: string;
90	}
91	
92	export async function listRuns(params?: {
93	  suite_id?: string;
94	  status?: RunStatus;
95	  limit?: number;
96	}): Promise<Run[]> {
97	  const { data } = await api.get<Run[]>('/runs', { params });
98	  return data;
99	}
100	
101	export async function getRun(runId: string): Promise<RunDetail> {
102	  const { data } = await api.get<RunDetail>(`/runs/${runId}`);
103	  return data;
104	}
105	
106	/**
107	 * Trigger a run of a suite (`POST /suites/{id}/run`). Edit-gated; returns the
108	 * queued `Run` (HTTP 202). The backend resolves the suite's target up front, so
109	 * a targetless/misconfigured suite fails with 422, and a broker outage with 503.
110	 */
111	export async function runSuite(suiteId: string): Promise<Run> {
112	  const { data } = await api.post<Run>(`/suites/${suiteId}/run`);
113	  return data;
114	}
115	
116	/**
117	 * Poll a run's live progress (`GET /runs/{id}/progress`). Suite-scoped (view).
118	 * Cheaper than `getRun` — no observed/expected payloads — so it's the call the
119	 * live-progress UI hits on its polling interval.
120	 */
121	export async function getRunProgress(runId: string): Promise<RunProgress> {
122	  const { data } = await api.get<RunProgress>(`/runs/${runId}/progress`);
123	  return data;
124	}
125	
126	/**
127	 * Cancel a non-terminal run (`POST /runs/{id}/cancel`). Edit-gated; returns the
128	 * updated `Run`. An already-finished run → 409. Cancel is cooperative (best-effort
129	 * for an in-flight run), so it may race a fast run to completion.
130	 */
131	export async function cancelRun(runId: string): Promise<Run> {
132	  const { data } = await api.post<Run>(`/runs/${runId}/cancel`);
133	  return data;
134	}
135	
136	export async function listPipelineRuns(params?: {
137	  provider?: 'adf' | 'airflow';
138	  status?: string;
139	  limit?: number;
140	}): Promise<PipelineRun[]> {
141	  const { data } = await api.get<PipelineRun[]>('/pipeline_runs', { params });
142	  return data;
143	}

